import{_ as a,o as n,c as e,ak as p}from"./chunks/framework.DwHlt8HN.js";const o=JSON.parse('{"title":"服务治理","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/governance/index.md","filePath":"distributed/governance/index.md","lastUpdated":1774319300000}'),l={name:"distributed/governance/index.md"};function i(r,s,c,t,b,d){return n(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="服务治理" tabindex="-1">服务治理 <a class="header-anchor" href="#服务治理" aria-label="Permalink to “服务治理”">​</a></h1><p>微服务拆分带来了灵活性，但也带来了复杂性。</p><ul><li>服务多了，怎么知道谁在调用谁？</li><li>下游服务挂了，上游怎么不被拖垮？</li><li>流量突然增大，怎么保护系统不被冲垮？</li></ul><p><strong>服务治理，就是来解决这些问题的。</strong></p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>服务治理分为两大类：基础设施治理和安全保障。</p><table tabindex="0"><thead><tr><th>章节</th><th>篇数</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/distributed/governance/service-discovery">服务发现与负载均衡</a></td><td>4 篇</td><td>服务发现、负载均衡策略、客户端 vs 服务端</td></tr><tr><td><a href="/distributed/governance/circuit-breaker">容错与保护</a></td><td>7 篇</td><td>熔断、降级、限流、超时、重试、幂等、安全</td></tr></tbody></table><h2 id="治理全景图" tabindex="-1">治理全景图 <a class="header-anchor" href="#治理全景图" aria-label="Permalink to “治理全景图”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>服务治理</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 服务发现</span></span>
<span class="line"><span>│   ├── 客户端发现 vs 服务端发现</span></span>
<span class="line"><span>│   ├── 健康检查与故障剔除</span></span>
<span class="line"><span>│   └── 服务注册与注销</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 负载均衡</span></span>
<span class="line"><span>│   ├── 策略：轮询、随机、哈希、最小连接</span></span>
<span class="line"><span>│   └── 客户端 LB vs 服务端 LB</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 容错保护</span></span>
<span class="line"><span>│   ├── 熔断：断路器模式</span></span>
<span class="line"><span>│   ├── 降级：多级降级策略</span></span>
<span class="line"><span>│   ├── 限流：单机 + 分布式限流</span></span>
<span class="line"><span>│   └── 超时：超时传递与最佳实践</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── 安全与幂等</span></span>
<span class="line"><span>    ├── 重试：退避算法</span></span>
<span class="line"><span>    ├── 幂等：接口幂等实现</span></span>
<span class="line"><span>    └── 接口安全：签名、认证、校验</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h2 id="核心问题-如何保护系统" tabindex="-1">核心问题：如何保护系统 <a class="header-anchor" href="#核心问题-如何保护系统" aria-label="Permalink to “核心问题：如何保护系统”">​</a></h2><p>分布式系统的故障传播，往往是灾难性的：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户请求 → 服务 A → 服务 B → 服务 C</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>                     C 突然变慢</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>                     B 等待超时</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>                     B 资源耗尽</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>                     A 也挂了</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>                     系统崩溃</span></span>
<span class="line"><span></span></span>
<span class="line"><span>这就是「雪崩效应」</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>保护系统的核心思路：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. 熔断：当下游持续失败，切断调用，保护自己</span></span>
<span class="line"><span>2. 降级：核心功能优先，非核心功能降级</span></span>
<span class="line"><span>3. 限流：控制进入系统的流量，不超过系统容量</span></span>
<span class="line"><span>4. 超时：避免无限等待，及时释放资源</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="面试高频问题" tabindex="-1">面试高频问题 <a class="header-anchor" href="#面试高频问题" aria-label="Permalink to “面试高频问题”">​</a></h2><h3 id="q1-熔断和降级的区别" tabindex="-1">Q1：熔断和降级的区别？ <a class="header-anchor" href="#q1-熔断和降级的区别" aria-label="Permalink to “Q1：熔断和降级的区别？”">​</a></h3><blockquote><p>「熔断是保护自己，降级是保护系统。 熔断当下游持续失败时，直接短路，不再调用下游。 降级是牺牲部分功能，保证核心功能可用。 两者配合：熔断触发 → 降级方案生效。」</p></blockquote><h3 id="q2-令牌桶和漏桶的区别" tabindex="-1">Q2：令牌桶和漏桶的区别？ <a class="header-anchor" href="#q2-令牌桶和漏桶的区别" aria-label="Permalink to “Q2：令牌桶和漏桶的区别？”">​</a></h3><blockquote><p>「漏桶以恒定速率处理请求，流量完全平滑。 令牌桶按固定速率生成令牌，请求必须拿到令牌才能处理。 令牌桶允许突发流量（桶容量内），漏桶不允许。 令牌桶适合「允许突发但有上限」的场景，漏桶适合「流量必须完全平稳」的场景。」</p></blockquote><h3 id="q3-如何保证接口幂等" tabindex="-1">Q3：如何保证接口幂等？ <a class="header-anchor" href="#q3-如何保证接口幂等" aria-label="Permalink to “Q3：如何保证接口幂等？”">​</a></h3><blockquote><p>「接口幂等的本质是：同一操作执行一次和执行多次，效果相同。 四种实现方案：</p><ol><li>Token + Redis：请求前获取 Token，提交时验证</li><li>唯一键约束：数据库主键 / 唯一索引</li><li>状态机：订单状态只能正向流转</li><li>分布式锁：锁住业务 ID 关键是要选择与业务匹配的方案，不是越多越好。」</li></ol></blockquote><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to “延伸阅读”">​</a></h2><p>服务治理是微服务架构的「基础设施」。</p><p>建议的学习顺序：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. 服务发现与健康检查（理解服务感知）</span></span>
<span class="line"><span>2. 负载均衡（理解流量分配）</span></span>
<span class="line"><span>3. 熔断与降级（理解系统保护）</span></span>
<span class="line"><span>4. 限流与超时（理解流量控制）</span></span>
<span class="line"><span>5. 重试与幂等（理解容错机制）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>记住：<strong>好的服务治理，让系统在故障面前「稳如泰山」。</strong></p>`,26)])])}const u=a(l,[["render",i]]);export{o as __pageData,u as default};
